var EventEmitter = require('eventemitter3');

var emitter = new EventEmitter();

module.exports = {
  addEventListener: function(listener) {
    emitter.on('change', listener);
    process.nextTick(function() {
      listener({ isConnected: true, type: 'wifi', isInternetReachable: true });
    });
    return function() { emitter.off('change', listener); };
  },
  fetch: function() {
    return Promise.resolve({ isConnected: true, type: 'wifi', isInternetReachable: true });
  }
};
